// Extract fields sent by AURA-WEAR FastAPI backend
const body = $input.first().json.body || $input.first().json;

const query      = body.query      || '';
const context    = body.context    || '';
const session_id = body.session_id || 'unknown';
const user_id    = body.user_id    || null;

// Build the system + user messages for the LLM
const systemPrompt = `You are AURA-AI, the official AI assistant for AURA-WEAR — a premium custom clothing brand based in Pakistan.

You help customers with:
- Fabric recommendations (Cotton, Fleece, Polyester, Blended)
- Garment types (T-Shirts, Hoodies, Jackets, Sports Uniforms)
- Print methods (DTG, Screen Print, Embroidery, Sublimation)
- Stitching styles and wash finishes
- Order tracking and status updates
- Pricing guidance
- General brand FAQs

IMPORTANT RULES:
- ONLY answer based on the database context provided below
- If context is empty or irrelevant, politely say you don't have that information
- Keep answers concise, friendly and professional
- Always respond in the same language as the customer's query
- For prices, always specify PKR currency
- Never make up product IDs, order IDs, or prices not found in context`;

const userMessage = `DATABASE CONTEXT (retrieved from AURA-WEAR database):
${context}

CUSTOMER QUESTION:
${query}`;

return [{
  json: {
    query,
    context,
    session_id,
    user_id,
    systemPrompt,
    userMessage
  }
}];

// Extract the AI reply from OpenAI response
const openaiData = $input.first().json;

// The reply may be nested differently depending on n8n OpenAI node version
let reply = '';

if (openaiData.message && openaiData.message.content) {
  reply = openaiData.message.content;
} else if (openaiData.choices && openaiData.choices[0]) {
  reply = openaiData.choices[0].message?.content || openaiData.choices[0].text || '';
} else if (openaiData.text) {
  reply = openaiData.text;
} else if (openaiData.content) {
  reply = openaiData.content;
} else {
  reply = 'I apologize, I was unable to generate a response. Please try again.';
}

return [{ json: { output: reply.trim() } }];
